import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"31. Study Leave","description":"","frontmatter":{"title":"31. Study Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","study-leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/education-pd/31-study-leave.md","filePath":"ebas/has-managers-admin/health-allied-services/education-pd/31-study-leave.md"}'),n={name:"ebas/has-managers-admin/health-allied-services/education-pd/31-study-leave.md"};function s(i,e,l,p,h,u){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_31-study-leave" tabindex="-1">31. Study Leave <a class="header-anchor" href="#_31-study-leave" aria-label="Permalink to &quot;31. Study Leave&quot;">​</a></h1><p><strong>31.1</strong> Quantum of study leave available</p><p><strong>(a)</strong> Employees will be entitled to four hours paid study leave per week up to a maximum of 26 weeks per annum, where undertaking study at Australian Qualification Framework Level 3 or above with an education institution or approved provider.</p><p><strong>31.2</strong> When paid study leave is available</p><p><strong>(a)</strong> Where the course of study is of relevance to the Employee’s employment, the Employer will not withhold consent.</p><p><strong>(b)</strong> Paid study leave may be taken as mutually agreed by, for example, 4 hours per week, 8 hours per fortnight or in blocks of 38 hours.</p><p><strong>(c)</strong> Paid study leave may, where mutually agreed, be used for the purpose of completing online or in-person components of the approved course, including for the purpose of undertaking placement that cannot be provided by their Employer.</p><p><strong>(d)</strong> A part-time Employee will be entitled to paid study leave on a pro-rata basis.</p><p><strong>(e)</strong> Paid study leave pursuant to this clause does not accumulate from year to year.</p><p><strong>(f)</strong> In all circumstances, the leave will be made available to the Employee(s) in the year in which application is made.</p><p><strong>31.3</strong> Application for paid study leave An Employee wishing to take study leave must:</p><p><strong>(a)</strong> apply in writing to the Employer as early as possible prior to the proposed leave date; and</p><p><strong>(b)</strong> Include with this application:</p><p><strong>(i)</strong> details of the course and institution in which the Employee is enrolled, or proposes to enrol; and</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>(ii)</strong> details of the relevance of the course to the Employee’s profession.</p><p><strong>31.4</strong> Response to application for paid study leave</p><p><strong>(a)</strong> The Employer will notify the Employee of whether or not their request for study leave has been approved within 7 days of the application being made.</p><p><strong>(b)</strong> Where the number of staff seeking to take study leave at any one time causes operational difficulties, the Employer and Employee(s) concerned will seek to reach agreement at a local level about the timeframe in which the leave is taken.</p><p><strong>(c)</strong> Any dispute arising under this clause 31 will be resolved in accordance with <a href="/eba/ebas/has-managers-admin/health-allied-services/allowances/17-reimbursement-of-expenses-dhsv.html">clause 17</a> (Dispute Resolution Procedure).</p><p><strong>31.5</strong> Temporary changes to existing contract to undertake study or employment opportunities</p><p><strong>(a)</strong> An Employee who has been engaged on a Full Time or Part Time basis with the Employer for at least twelve months may request temporary changes to their existing contract of employment for the purpose of undertaking study or an employment opportunity outside the Employer that is of benefit to the career pathway of the Employee within the public health sector.</p><p><strong>(b)</strong> For the purpose of this clause, temporary changes mean the following:</p><p><strong>(i)</strong> an unpaid leave of absence for no longer than twelve months,</p><p><strong>(ii)</strong> a variation to their existing contract of employment to reduce their working hours for no longer than twelve months</p><p><strong>(iii)</strong> a request to flexibly use accrued Long Service Leave or Annual Leave for the purpose of reducing the number of days worked or their working hours but retaining their previous employment status</p><p><strong>(c)</strong> For the purpose of Long Service Leave, an unpaid leave of absence taken in accordance with this clause for up to twelve months with the approval of the Employer will not count towards service, however it will not break service.</p><p><strong>(d)</strong> An Employee may only request temporary changes in accordance with this clause for one course of study or employment opportunity over the life of this Agreement unless otherwise agreed by the Employer.</p><p><strong>(e)</strong> Where mutually agreed, the Employee may request temporary changes to their existing contract of employment for multiple periods, the quantum of which does not exceed twelve months over the life of this Agreement.</p><p>Plain language terms: exam leave, education leave.</p>',30)])])}const c=t(n,[["render",s]]);export{m as __pageData,c as default};
